func (r *TaskGrantResourceModel) ToSharedTaskServiceCreateGrantRequest(ctx context.Context) (*shared.TaskServiceCreateGrantRequest, diag.Diagnostics) {
	var diags diag.Diagnostics

	var appEntitlementID string
	appEntitlementID = r.AppEntitlementID.ValueString()

	var appID string
	appID = r.AppID.ValueString()

	appUserID := new(string)
	if !r.AppUserID.IsUnknown() && !r.AppUserID.IsNull() {
		*appUserID = r.AppUserID.ValueString()
	} else {
		appUserID = nil
	}
	description := new(string)
	if !r.Description.IsUnknown() && !r.Description.IsNull() {
		*description = r.Description.ValueString()
	} else {
		description = nil
	}
	emergencyAccess := new(bool)
	if !r.EmergencyAccess.IsUnknown() && !r.EmergencyAccess.IsNull() {
		*emergencyAccess = r.EmergencyAccess.ValueBool()
	} else {
		emergencyAccess = nil
	}
	grantDuration := new(string)
	if !r.GrantDuration.IsUnknown() && !r.GrantDuration.IsNull() {
		*grantDuration = r.GrantDuration.ValueString()
	} else {
		grantDuration = nil
	}
	identityUserID := new(string)
	if !r.IdentityUserID.IsUnknown() && !r.IdentityUserID.IsNull() {
		*identityUserID = r.IdentityUserID.ValueString()
	} else {
		identityUserID = nil
	}
	var requestData *shared.RequestData
	if r.RequestData != nil {
		requestData = &shared.RequestData{}
	}
	var taskGrantSource *shared.TaskGrantSource
	if r.TaskGrantSource != nil {
		conversationID := new(string)
		if !r.TaskGrantSource.ConversationID.IsUnknown() && !r.TaskGrantSource.ConversationID.IsNull() {
			*conversationID = r.TaskGrantSource.ConversationID.ValueString()
		} else {
			conversationID = nil
		}
		externalURL := new(string)
		if !r.TaskGrantSource.ExternalURL.IsUnknown() && !r.TaskGrantSource.ExternalURL.IsNull() {
			*externalURL = r.TaskGrantSource.ExternalURL.ValueString()
		} else {
			externalURL = nil
		}
		integrationID := new(string)
		if !r.TaskGrantSource.IntegrationID.IsUnknown() && !r.TaskGrantSource.IntegrationID.IsNull() {
			*integrationID = r.TaskGrantSource.IntegrationID.ValueString()
		} else {
			integrationID = nil
		}
		isExtension := new(bool)
		if !r.TaskGrantSource.IsExtension.IsUnknown() && !r.TaskGrantSource.IsExtension.IsNull() {
			*isExtension = r.TaskGrantSource.IsExtension.ValueBool()
		} else {
			isExtension = nil
		}
		requestID := new(string)
		if !r.TaskGrantSource.RequestID.IsUnknown() && !r.TaskGrantSource.RequestID.IsNull() {
			*requestID = r.TaskGrantSource.RequestID.ValueString()
		} else {
			requestID = nil
		}
		taskGrantSource = &shared.TaskGrantSource{
			ConversationID: conversationID,
			ExternalURL:    externalURL,
			IntegrationID:  integrationID,
			IsExtension:    isExtension,
			RequestID:      requestID,
		}
	}
	out := shared.TaskServiceCreateGrantRequest{
		AppEntitlementID: appEntitlementID,
		AppID:            appID,
		AppUserID:        appUserID,
		Description:      description,
		EmergencyAccess:  emergencyAccess,
		GrantDuration:    grantDuration,
		IdentityUserID:   identityUserID,
		RequestData:      requestData,
		TaskGrantSource:  taskGrantSource,
	}

	return &out, diags
}
